def apply_action(action, payload=None):
    if action == "turn_on":
        device_state["power"] = True
        device_state["last_action"] = action
        return {"ok": True, "state": "on"}
    if action == "turn_off":
        device_state["power"] = False
        device_state["last_action"] = action
